import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import { ElMessageBox, ElMessage } from 'element-plus';
import userService from '@/services/user';
import novelService from '@/services/novel';
export default {
  name: 'MyNovelsView',
  data() {
    return {
      novels: [],
      loading: true,
      error: null,
      selectedNovel: null
    };
  },
  created() {
    this.fetchUserNovels();
  },
  methods: {
    async fetchUserNovels() {
      this.loading = true;
      this.error = null;
      try {
        const data = await userService.getUserNovels();
        console.log('获取用户小说原始响应:', data);

        // 确保正确处理返回格式
        let novels = [];
        if (data) {
          if (Array.isArray(data)) {
            novels = data;
          } else if (data.novels && Array.isArray(data.novels)) {
            novels = data.novels;
          }
        }
        this.novels = novels;
        console.log('获取用户小说成功:', this.novels);
      } catch (error) {
        console.error('获取小说列表失败:', error);
        if (error.message === '未登录' || error.message === '用户ID不存在') {
          this.error = '请先登录后再查看您的小说';

          // 可选：重定向到登录页
          setTimeout(() => {
            this.$router.push('/login?redirect=/my-novels');
          }, 2000);
        } else {
          this.error = error.response?.data?.error || '获取小说列表失败，请稍后重试';
        }

        // 如果获取失败设置空列表
        this.novels = [];
      } finally {
        this.loading = false;
      }
    },
    formatDate(dateString) {
      if (!dateString) return '未知';
      const date = new Date(dateString);
      return date.toLocaleDateString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      });
    },
    getStatusText(status) {
      const statusMap = {
        'PENDING': '待处理',
        'PROCESSING': '处理中',
        'COMPLETED': '已完成',
        'FAILED': '处理失败'
      };
      return statusMap[status] || status;
    },
    getStatusBadgeClass(status) {
      const classMap = {
        'PENDING': 'badge bg-warning',
        'PROCESSING': 'badge bg-info',
        'COMPLETED': 'badge bg-success',
        'FAILED': 'badge bg-danger'
      };
      return classMap[status] || 'badge bg-secondary';
    },
    goToAnalyze(novelId) {
      this.$router.push(`/analyze/${novelId}`);
    },
    confirmDelete(novel) {
      this.selectedNovel = novel;
      ElMessageBox.confirm(`您确定要删除小说 "${novel.title}" 吗？此操作不可逆，删除后将无法恢复！`, '确认删除', {
        confirmButtonText: '确认删除',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        this.deleteNovel();
      }).catch(() => {
        // 用户取消，不执行操作
      });
    },
    async deleteNovel() {
      if (!this.selectedNovel) return;
      try {
        await novelService.deleteNovel(this.selectedNovel.id);
        this.novels = this.novels.filter(novel => novel.id !== this.selectedNovel.id);
        ElMessage({
          type: 'success',
          message: '小说删除成功'
        });
      } catch (error) {
        console.error('删除小说失败:', error);
        ElMessage({
          type: 'error',
          message: error.response?.data?.error || '删除小说失败，请稍后重试'
        });
      } finally {
        this.selectedNovel = null;
      }
    }
  }
};
